#include "../include/cell_view.h"
#include "../include/topo_link.h"

#include <string.h>

int step_n(CellGrid *a, const int *b, int c, TopoLink *d) {
    if (!a || !d) return -1;
    int n = a->n;
    /* Clear child info */
    memset(d->child0, 0, sizeof(d->child0));
    memset(d->child_count, 0, sizeof(d->child_count));
    for (int i = 0; i < n; i++) {
        d->parent[i] = a->cells[i].parent;
    }
    /* Build child0 and child_count from parent info */
    for (int i = 0; i < n; i++) {
        int p = d->parent[i];
        if (p < 0) continue;
        if (d->child_count[p] == 0) {
            d->child0[p] = i;
        }
        d->child_count[p]++;
    }
    (void)b;
    (void)c;
    return 0;
}
